import{_ as a,o,c as s,ae as t}from"./chunks/framework.C7FLYIpo.js";const g=JSON.parse('{"title":"온보딩 (CLI)","description":"게이트웨이, 워크스페이스, 채널 및 스킬을 위한 CLI 안내 설정","frontmatter":{"title":"온보딩 (CLI)","description":"게이트웨이, 워크스페이스, 채널 및 스킬을 위한 CLI 안내 설정"},"headers":[],"relativePath":"start/wizard.md","filePath":"start/wizard.md","lastUpdated":null}'),i={name:"start/wizard.md"};function l(n,e,c,r,d,p){return o(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="온보딩-cli" tabindex="-1">온보딩 (CLI) <a class="header-anchor" href="#온보딩-cli" aria-label="Permalink to &quot;온보딩 (CLI)&quot;">​</a></h1><p>CLI 온보딩은 macOS, Linux 또는 Windows (WSL2를 통해; 강력히 권장)에서 OpenClaw를 설정하는 <strong>권장</strong> 방법입니다. 하나의 안내 흐름으로 로컬 Gateway 또는 원격 Gateway 연결과 채널, 스킬 및 워크스페이스 기본값을 구성합니다.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> onboard</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">INFO</p><p>가장 빠른 첫 번째 채팅: Control UI를 여십시오 (채널 설정 불필요). <code>openclaw dashboard</code>를 실행하고 브라우저에서 채팅하십시오. 문서: <a href="/openclaw-docs-ko/web/dashboard">대시보드</a>.</p></div><p>나중에 재구성하려면:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> configure</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> agents</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&amp;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">NOTE</p><p><code>--json</code>은 비대화형 모드를 의미하지 않습니다. 스크립트에는 <code>--non-interactive</code>를 사용하십시오.</p></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>CLI 온보딩에는 Brave, DuckDuckGo, Exa, Firecrawl, Gemini, Grok, Kimi, MiniMax Search, Ollama Web Search, Perplexity, SearXNG 또는 Tavily와 같은 프로바이더를 선택할 수 있는 웹 검색 단계가 포함됩니다. 일부 프로바이더는 API 키가 필요하고 다른 일부는 키가 필요 없습니다. <code>openclaw configure --section web</code>으로 나중에 구성할 수도 있습니다. 문서: <a href="/openclaw-docs-ko/tools/web">웹 도구</a>.</p></div><h2 id="빠른-시작-vs-고급" tabindex="-1">빠른 시작 vs 고급 <a class="header-anchor" href="#빠른-시작-vs-고급" aria-label="Permalink to &quot;빠른 시작 vs 고급&quot;">​</a></h2><p>온보딩은 <strong>빠른 시작</strong> (기본값) vs <strong>고급</strong> (전체 제어)으로 시작합니다.</p><p><strong>빠른 시작 (기본값)</strong></p><ul><li><p>로컬 게이트웨이 (루프백)</p><ul><li>워크스페이스 기본값 (또는 기존 워크스페이스)</li><li>게이트웨이 포트 <strong>18789</strong></li><li>게이트웨이 인증 <strong>토큰</strong> (자동 생성, 루프백에서도)</li><li>새 로컬 설정의 기본 도구 정책: <code>tools.profile: &quot;coding&quot;</code> (기존 명시적 프로파일은 보존됩니다)</li><li>DM 격리 기본값: 로컬 온보딩은 설정되지 않은 경우 <code>session.dmScope: &quot;per-channel-peer&quot;</code>를 작성합니다. 자세한 내용: <a href="/openclaw-docs-ko/start/wizard-cli-reference#outputs-and-internals">CLI 설정 참조</a></li><li>Tailscale 노출 <strong>끄기</strong></li><li>Telegram + WhatsApp DM은 기본적으로 <strong>허용 목록</strong>을 사용합니다 (전화번호를 입력하도록 요청합니다)</li></ul><p><strong>고급 (전체 제어)</strong></p></li><li><p>모든 단계를 노출합니다 (모드, 워크스페이스, 게이트웨이, 채널, 데몬, 스킬).</p></li></ul><h2 id="온보딩이-구성하는-항목" tabindex="-1">온보딩이 구성하는 항목 <a class="header-anchor" href="#온보딩이-구성하는-항목" aria-label="Permalink to &quot;온보딩이 구성하는 항목&quot;">​</a></h2><p>**로컬 모드 (기본값)**는 다음 단계를 안내합니다:</p><ol><li><strong>모델/인증</strong> — 지원되는 모든 프로바이더/인증 흐름을 선택합니다 (API 키, OAuth 또는 프로바이더별 수동 인증), Custom Provider 포함 (OpenAI 호환, Anthropic 호환 또는 알 수 없음 자동 감지). 기본 모델을 선택합니다. 보안 참고: 이 에이전트가 도구를 실행하거나 웹훅/훅 콘텐츠를 처리할 경우, 사용 가능한 가장 강력한 최신 세대 모델을 선호하고 도구 정책을 엄격하게 유지하십시오. 약한/오래된 티어는 프롬프트 인젝션이 더 쉽습니다. 비대화형 실행의 경우, <code>--secret-input-mode ref</code>는 평문 API 키 값 대신 환경 변수 기반 참조를 인증 프로파일에 저장합니다. 비대화형 <code>ref</code> 모드에서, 프로바이더 환경 변수가 설정되어 있어야 합니다; 해당 환경 변수 없이 인라인 키 플래그를 전달하면 빠르게 실패합니다. 대화형 실행에서, 비밀 참조 모드를 선택하면 환경 변수 또는 구성된 프로바이더 참조 (<code>file</code> 또는 <code>exec</code>)를 가리킬 수 있으며, 저장 전 빠른 사전 검증이 실행됩니다. Anthropic의 경우, 대화형 온보딩/구성은 기본 로컬 경로로 <strong>Anthropic Claude CLI</strong>를 제공하고 권장 프로덕션 경로로 <strong>Anthropic API 키</strong>를 제공합니다. Anthropic 설정 토큰도 지원되는 토큰 인증 경로로 계속 사용 가능합니다.</li><li><strong>워크스페이스</strong> — 에이전트 파일의 위치 (기본값 <code>~/.openclaw/workspace</code>). 부트스트랩 파일을 초기화합니다.</li><li><strong>Gateway</strong> — 포트, 바인드 주소, 인증 모드, Tailscale 노출. 대화형 토큰 모드에서, 기본 평문 토큰 저장 또는 SecretRef 옵트인을 선택합니다. 비대화형 토큰 SecretRef 경로: <code>--gateway-token-ref-env &amp;lt;ENV_VAR&amp;gt;</code>.</li><li><strong>채널</strong> — BlueBubbles, Discord, Feishu, Google Chat, Mattermost, Microsoft Teams, QQ Bot, Signal, Slack, Telegram, WhatsApp 등의 내장 및 번들 채팅 채널.</li><li><strong>데몬</strong> — LaunchAgent (macOS), systemd 사용자 유닛 (Linux/WSL2) 또는 사용자별 Startup 폴더 대체 기능이 있는 네이티브 Windows 예약 작업을 설치합니다. 토큰 인증에 토큰이 필요하고 <code>gateway.auth.token</code>이 SecretRef로 관리되는 경우, 데몬 설치가 이를 검증하지만 확인된 토큰을 감독자 서비스 환경 메타데이터에 유지하지 않습니다. 토큰 인증에 토큰이 필요하고 구성된 토큰 SecretRef가 확인되지 않은 경우, 데몬 설치가 실행 가능한 안내와 함께 차단됩니다. <code>gateway.auth.token</code>과 <code>gateway.auth.password</code> 모두 구성되어 있고 <code>gateway.auth.mode</code>가 설정되지 않은 경우, 모드가 명시적으로 설정될 때까지 데몬 설치가 차단됩니다.</li><li><strong>헬스 체크</strong> — Gateway를 시작하고 실행 중인지 확인합니다.</li><li><strong>스킬</strong> — 권장 스킬 및 선택적 의존성을 설치합니다.</li></ol><div class="info custom-block"><p class="custom-block-title">NOTE</p><p>온보딩을 다시 실행해도 명시적으로 <strong>재설정</strong>을 선택 (또는 <code>--reset</code>을 전달)하지 않는 한 아무것도 지우지 <strong>않습니다</strong>. CLI <code>--reset</code>은 기본적으로 구성, 자격 증명 및 세션을 재설정합니다; 워크스페이스를 포함하려면 <code>--reset-scope full</code>을 사용하십시오. 구성이 잘못되었거나 레거시 키가 포함된 경우, 온보딩은 먼저 <code>openclaw doctor</code>를 실행하도록 요청합니다.</p></div><p><strong>원격 모드</strong>는 로컬 클라이언트가 다른 곳의 Gateway에 연결하도록만 구성합니다. 원격 호스트에서는 아무것도 설치하거나 변경하지 <strong>않습니다</strong>.</p><h2 id="다른-에이전트-추가" tabindex="-1">다른 에이전트 추가 <a class="header-anchor" href="#다른-에이전트-추가" aria-label="Permalink to &quot;다른 에이전트 추가&quot;">​</a></h2><p><code>openclaw agents add &amp;lt;name&amp;gt;</code>을 사용하여 자체 워크스페이스, 세션 및 인증 프로파일을 가진 별도의 에이전트를 생성하십시오. <code>--workspace</code> 없이 실행하면 온보딩이 시작됩니다.</p><p>설정 항목:</p><ul><li><code>agents.list[].name</code></li><li><code>agents.list[].workspace</code></li><li><code>agents.list[].agentDir</code></li></ul><p>참고:</p><ul><li>기본 워크스페이스는 <code>~/.openclaw/workspace-&amp;lt;agentId&amp;gt;</code>를 따릅니다.</li><li>인바운드 메시지 라우팅을 위해 <code>bindings</code>를 추가하십시오 (온보딩이 이를 수행할 수 있습니다).</li><li>비대화형 플래그: <code>--model</code>, <code>--agent-dir</code>, <code>--bind</code>, <code>--non-interactive</code>.</li></ul><h2 id="전체-참조" tabindex="-1">전체 참조 <a class="header-anchor" href="#전체-참조" aria-label="Permalink to &quot;전체 참조&quot;">​</a></h2><p>단계별 세부 분류 및 구성 출력에 대해서는 <a href="/openclaw-docs-ko/start/wizard-cli-reference">CLI 설정 참조</a>를 참조하십시오. 비대화형 예시는 <a href="/openclaw-docs-ko/start/wizard-cli-automation">CLI 자동화</a>를 참조하십시오. RPC 세부 정보를 포함한 더 깊은 기술 참조는 <a href="/openclaw-docs-ko/reference/wizard">온보딩 참조</a>를 참조하십시오.</p><h2 id="관련-문서" tabindex="-1">관련 문서 <a class="header-anchor" href="#관련-문서" aria-label="Permalink to &quot;관련 문서&quot;">​</a></h2><ul><li>CLI 명령 참조: <a href="/openclaw-docs-ko/cli/onboard"><code>openclaw onboard</code></a></li><li>온보딩 개요: <a href="/openclaw-docs-ko/start/onboarding-overview">온보딩 개요</a></li><li>macOS 앱 온보딩: <a href="/openclaw-docs-ko/start/onboarding">온보딩</a></li><li>에이전트 최초 실행 의식: <a href="/openclaw-docs-ko/start/bootstrapping">에이전트 부트스트랩</a></li></ul>`,27)])])}const k=a(i,[["render",l]]);export{g as __pageData,k as default};
